import{_ as t,o as r,c as o,a2 as a}from"./chunks/framework.DYQ4mM3C.js";const u=JSON.parse('{"title":"Threat Model","description":"","frontmatter":{},"headers":[],"relativePath":"threat-model.md","filePath":"threat-model.md","lastUpdated":1783311890000}'),i={name:"threat-model.md"};function l(s,e,n,d,c,h){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="threat-model" tabindex="-1">Threat Model <a class="header-anchor" href="#threat-model" aria-label="Permalink to &quot;Threat Model&quot;">​</a></h1><p>EnvVault protects long-lived local credential material from routine project and <code>.env</code> exposure. It does not defend against a fully compromised OS user account.</p><h2 id="assets" tabindex="-1">Assets <a class="header-anchor" href="#assets" aria-label="Permalink to &quot;Assets&quot;">​</a></h2><ul><li>Credential values stored in the OS credential store.</li><li>Credential files inside temporary isolated-home workspaces while a child process is running.</li><li>Local proxy bearer tokens while the child process is running.</li><li>EnvVault config policy and project-binding approvals.</li></ul><h2 id="trust-boundaries" tabindex="-1">Trust Boundaries <a class="header-anchor" href="#trust-boundaries" aria-label="Permalink to &quot;Trust Boundaries&quot;">​</a></h2><ul><li>OS credential store: stores long-lived raw secrets.</li><li>EnvVault config directory: stores non-secret settings and optional proxy policy.</li><li>Child process environment: receives resolved credential values or local proxy bearer tokens.</li><li>Isolated home workspace: receives credential values requested with <code>--home-file</code> and becomes the child process&#39;s home without copying or writing the requested destination under the real home directory.</li><li>Localhost provider proxy: accepts local proxy bearer tokens and adds provider API keys for allowlisted requests.</li><li>Third-party provider API: receives the real provider API key from the child process or proxy.</li></ul><h2 id="in-scope" tabindex="-1">In Scope <a class="header-anchor" href="#in-scope" aria-label="Permalink to &quot;In Scope&quot;">​</a></h2><ul><li>Accidental commit of <code>.env</code> files containing <code>envvault://</code> references.</li><li>Third-party SDKs that expect normal API key environment variables.</li><li>Third-party tools that require credential files at fixed paths below their home directory.</li><li>Third-party SDKs that can be configured with both a custom base URL and bearer token.</li><li>Repository changes that try to request a different credential, proxy target URL, method, or path.</li><li>Child processes that can inspect their own environment.</li></ul><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>Malicious code running as the same OS user with arbitrary process and keychain access.</li><li>Kernel, hypervisor, firmware, or hardware compromise.</li><li>Browser compromise or malicious browser extensions.</li><li>Application-level data written using a valid credential.</li><li>DLP for prompts, stdout, stderr, HTTP request bodies, or third-party application logs.</li><li>Keeping a credential out of the child process when an SDK or tool requires the raw credential directly and cannot be pointed at the EnvVault localhost proxy.</li></ul><h2 id="security-controls" tabindex="-1">Security Controls <a class="header-anchor" href="#security-controls" aria-label="Permalink to &quot;Security Controls&quot;">​</a></h2><ul><li>Credential values are stored in the OS credential store.</li><li>Direct references use strict <code>envvault://&lt;credential&gt;</code> parsing.</li><li><code>.env</code> references reject query strings, fragments, path traversal, and percent-encoded separators.</li><li><code>--home-file</code> accepts only safe relative destination paths and creates a private, otherwise empty home. Template sources may be relative to the invocation working directory or absolute; source files must be regular files and may not be symlinks.</li><li>Home-file JSON, YAML, and TOML resolution replaces only whole-string direct credential references in values, never keys. It rejects embedded or proxy references, ambiguous input, non-string YAML mapping keys, and unsupported YAML anchors, aliases, and merge keys; credentials are safely encoded as strings and results are written with user-only permissions. Source templates are not modified or written back.</li><li>Isolated-home workspaces are removed after normal child exit. Stale workspaces left by forced termination or system failure are removed by <code>envvault doctor --repair</code>.</li><li>Optional proxy policy fixes target URL, allowed HTTP methods, allowed paths, and local token lifetime.</li><li>Proxy <code>.env</code> references split proxy base URLs from local-only bearer tokens.</li><li>Non-interactive unapproved project bindings fail closed for proxy use.</li><li>Audit records are metadata-only.</li></ul><h2 id="residual-risk" tabindex="-1">Residual Risk <a class="header-anchor" href="#residual-risk" aria-label="Permalink to &quot;Residual Risk&quot;">​</a></h2><p>Direct credential mode places the credential value in the child process environment. It improves repository and <code>.env</code> hygiene but does not hide that credential from the launched process.</p><p>Isolated home-file mode likewise does not hide a credential from the child: the child can read every injected file. A forced termination or system failure can leave the private workspace on disk until <code>envvault doctor --repair</code> removes it. The source template contains references rather than secrets and remains unchanged; child modifications to the normalized resolved copy are discarded. Because the isolated home starts empty, a child that needs unrelated files from the real home must be configured explicitly rather than relying on them. The isolation changes home and config environment variables; it does not mount or sandbox the filesystem. A child that independently resolves the OS account home can still access it. The workspace lifetime follows the direct child, so a daemonized descendant does not keep the workspace alive.</p><p>Local proxy tokens are bearer tokens. Anyone who obtains one can use it until it expires, subject to the proxy allowlist.</p>',16)])])}const m=t(i,[["render",l]]);export{u as __pageData,m as default};
